---

**Note:**  
The original error was caused by declaring a `static` inner class inside a method, which is not allowed in Java. The fixed version removes the `static` modifier from the inner class in `testIsInnerClass_withMemberStaticClass`. If you want to test a static member class, you need to declare it as a static nested class inside a top-level class or the test class itself, not inside a method. Here is an alternative approach if you want to test a static nested class:

```java
package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import org.junit.jupiter.api.Test;

class ExcluderTest {

  static class OuterStatic {
    static class StaticInner {}
  }

  class OuterNonStatic {
    class Inner {}
  }

  @Test
  void testIsInnerClass_withMemberStaticClass() throws Exception {
    Excluder excluder = new Excluder();
    Class<?> clazz = OuterStatic.StaticInner.class;

    boolean result = (boolean) Excluder.class.getDeclaredMethod("isInnerClass", Class.class)
        .invoke(excluder, clazz);
    assertFalse(result);
  }

  @Test
  void testIsInnerClass_withMemberNonStaticClass() throws Exception {
    Excluder excluder = new Excluder();
    Class<?> clazz = OuterNonStatic.Inner.class;

    boolean result = (boolean) Excluder.class.getDeclaredMethod("isInnerClass", Class.class)
        .invoke(excluder, clazz);
    assertTrue(result);
  }

  @Test
  void testIsInnerClass_withNonMemberClass() throws Exception {
    class LocalClass {}
    Excluder excluder = new Excluder();
    Class<?> clazz = LocalClass.class;

    boolean result = (boolean) Excluder.class.getDeclaredMethod("isInnerClass", Class.class)
        .invoke(excluder, clazz);
    assertFalse(result);
  }

  @Test
  void testIsInnerClass_withAnonymousClass() throws Exception {
    Excluder excluder = new Excluder();
    Object anonymous = new Object() {};
    Class<?> clazz = anonymous.getClass();

    boolean result = (boolean) Excluder.class.getDeclaredMethod("isInnerClass", Class.class)
        .invoke(excluder, clazz);
    assertFalse(result);
  }
}
```

Use this version if you want to keep the static inner class test.
